// Solution
function attachDynamicRoutes(router, routes) {
  for (let route in routes) {
    // Fix: Use the router.use method to attach a middleware function that resolves the dynamic route
    router.use(route, (req, res, next) => {
      routes[route](req, res, next);
    });
  }
}

// Export the attachDynamicRoutes function
module.exports = attachDynamicRoutes;

// Example usage:
const express = require('express');
const router = express.Router();
const attachDynamicRoutes = require('./attachDynamicRoutes');

const routes = {
  '/': (req, res, next) => res.send('Home'),
  '/about': (req, res, next) => res.send('About')
};

attachDynamicRoutes(router, routes);

router.listen(3000, () => {
  console.log('Server listening on port 3000');
});
